    ret["hiv_births"] = state.hiv_births;
    const int py_rank_prevalence_15to49_hts = 1;
    size_t py_dims_prevalence_15to49_hts[py_rank_prevalence_15to49_hts] = { SS::HIV_STEPS_PER_YEAR };
